((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka janganlah ucapan mereka menyedihkan kamu. Sesungguhnya Kami mengetahui apa yang mereka rahasiakan dan apa yang mereka nyatakan.', NOW(), NOW()),
