((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tuhan langit dan bumi dan apa yang berada di antara keduanya dan Tuhan tempat-tempat terbit matahari.', NOW(), NOW()),
