((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 138), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan di waktu malam. Maka apakah kamu tidak memikirkan?', NOW(), NOW()),
