((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 140), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(ingatlah) ketika ia lari, ke kapal yang penuh muatan,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 141), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kemudian ia ikut berundi lalu dia termasuk orang-orang yang kalah dalam undian.', NOW(), NOW()),
