((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 145), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian Kami lemparkan dia ke daerah yang tandus, sedang ia dalam keadaan sakit.', NOW(), NOW()),
