((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 147), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami utus dia kepada seratus ribu orang atau lebih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 148), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Lalu mereka beriman, karena itu Kami anugerahkan kenikmatan hidup kepada mereka hingga waktu yang tertentu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 149), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tanyakanlah (ya Muhammad) kepada mereka (orang-orang kafir Mekah): "Apakah untuk Tuhanmu anak-anak perempuan dan untuk mereka anak laki-laki,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 150), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'atau apakah Kami menciptakan malaikat-malaikat berupa perempuan dan mereka menyaksikan(nya)?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 151), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ketahuilah bahwa sesungguhnya mereka dengan kebohongannya benar-benar mengatakan:', NOW(), NOW()),
